CREATE OR REPLACE FUNCTION fn_auditoria_pedido()
RETURNS TRIGGER AS $func$
BEGIN
    IF (TG_OP = 'INSERT') THEN
        INSERT INTO pedido_auditoria(pedido_id,estado_anterior,estado_nuevo,total_anterior,total_nuevo,operacion,modificado_en)
        VALUES(NEW.id,NULL,NEW.estado::TEXT,NULL,NEW.total,'INSERT',NOW());
        RETURN NEW;
    ELSIF (TG_OP = 'UPDATE') THEN
        IF OLD.estado IS DISTINCT FROM NEW.estado OR OLD.total IS DISTINCT FROM NEW.total THEN
            INSERT INTO pedido_auditoria(pedido_id,estado_anterior,estado_nuevo,total_anterior,total_nuevo,operacion,modificado_en)
            VALUES(NEW.id,OLD.estado::TEXT,NEW.estado::TEXT,OLD.total,NEW.total,'UPDATE',NOW());
        END IF;
        RETURN NEW;
    ELSIF (TG_OP = 'DELETE') THEN
        INSERT INTO pedido_auditoria(pedido_id,estado_anterior,estado_nuevo,total_anterior,total_nuevo,operacion,modificado_en)
        VALUES(OLD.id,OLD.estado::TEXT,'ELIMINADO',OLD.total,NULL,'DELETE',NOW());
        RETURN OLD;
    END IF;
    RETURN NULL;
END;
$func$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_auditoria_pedido ON pedido;
CREATE TRIGGER trg_auditoria_pedido
    AFTER INSERT OR UPDATE OR DELETE ON pedido
    FOR EACH ROW EXECUTE FUNCTION fn_auditoria_pedido();

CREATE OR REPLACE FUNCTION fn_auditoria_cliente()
RETURNS TRIGGER AS $func$
BEGIN
    IF (TG_OP = 'INSERT') THEN
        INSERT INTO cliente_auditoria(cliente_id,nombre_anterior,nombre_nuevo,email_anterior,email_nuevo,activo_anterior,activo_nuevo,operacion,modificado_en)
        VALUES(NEW.id,NULL,NEW.nombre,NULL,NEW.email,NULL,NEW.activo,'INSERT',NOW());
        RETURN NEW;
    ELSIF (TG_OP = 'UPDATE') THEN
        INSERT INTO cliente_auditoria(cliente_id,nombre_anterior,nombre_nuevo,email_anterior,email_nuevo,activo_anterior,activo_nuevo,operacion,modificado_en)
        VALUES(NEW.id,OLD.nombre,NEW.nombre,OLD.email,NEW.email,OLD.activo,NEW.activo,'UPDATE',NOW());
        RETURN NEW;
    ELSIF (TG_OP = 'DELETE') THEN
        INSERT INTO cliente_auditoria(cliente_id,nombre_anterior,nombre_nuevo,email_anterior,email_nuevo,activo_anterior,activo_nuevo,operacion,modificado_en)
        VALUES(OLD.id,OLD.nombre,NULL,OLD.email,NULL,OLD.activo,NULL,'DELETE',NOW());
        RETURN OLD;
    END IF;
    RETURN NULL;
END;
$func$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_auditoria_cliente ON cliente;
CREATE TRIGGER trg_auditoria_cliente
    AFTER INSERT OR UPDATE OR DELETE ON cliente
    FOR EACH ROW EXECUTE FUNCTION fn_auditoria_cliente();

CREATE OR REPLACE FUNCTION fn_total_facturado_cliente(p_cliente_id BIGINT)
RETURNS NUMERIC(12,2) AS $func$
DECLARE v_total NUMERIC(12,2);
BEGIN
    SELECT COALESCE(SUM(total),0) INTO v_total
    FROM pedido WHERE cliente_id = p_cliente_id AND estado = 'PAGADO';
    RETURN v_total;
END;
$func$ LANGUAGE plpgsql STABLE;

CREATE OR REPLACE FUNCTION fn_validar_transicion_estado()
RETURNS TRIGGER AS $func$
BEGIN
    IF TG_OP = 'UPDATE' AND OLD.estado IS DISTINCT FROM NEW.estado THEN
        IF OLD.estado = 'PAGADO' THEN
            RAISE EXCEPTION 'Un pedido PAGADO no puede cambiar de estado';
        END IF;
        IF OLD.estado = 'CANCELADO' THEN
            RAISE EXCEPTION 'Un pedido CANCELADO no puede cambiar de estado';
        END IF;
        IF OLD.estado = 'CREADO' AND NEW.estado NOT IN ('CONFIRMADO','CANCELADO') THEN
            RAISE EXCEPTION 'Desde CREADO solo se puede pasar a CONFIRMADO o CANCELADO';
        END IF;
        IF OLD.estado = 'CONFIRMADO' AND NEW.estado NOT IN ('PAGADO','CANCELADO') THEN
            RAISE EXCEPTION 'Desde CONFIRMADO solo se puede pasar a PAGADO o CANCELADO';
        END IF;
    END IF;
    RETURN NEW;
END;
$func$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_validar_estado_pedido ON pedido;
CREATE TRIGGER trg_validar_estado_pedido
    BEFORE UPDATE ON pedido
    FOR EACH ROW EXECUTE FUNCTION fn_validar_transicion_estado();

CREATE OR REPLACE FUNCTION fn_resumen_pedidos()
RETURNS TABLE(estado TEXT, cantidad BIGINT, total_acumulado NUMERIC(12,2)) AS $func$
BEGIN
    RETURN QUERY
    SELECT p.estado::TEXT, COUNT(*)::BIGINT, COALESCE(SUM(p.total),0)::NUMERIC(12,2)
    FROM pedido p GROUP BY p.estado ORDER BY p.estado;
END;
$func$ LANGUAGE plpgsql STABLE;
